// src/pages/Login.jsx

import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [role, setRole] =
    useState("customer");

  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(

        "http://localhost:5000/api/auth/login",

        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(

        "user",

        JSON.stringify(res.data.user)

      );

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");

      }

    } catch (err) {

      alert("Invalid Credentials");

    }
  };

  return (

    <div style={styles.page}>

      {/* LEFT SIDE */}

      <div style={styles.leftSection}>

        <div style={styles.overlay}></div>

        <div style={styles.leftContent}>

          <div style={styles.logoBox}>

            <div style={styles.logoCircle}>
              D
            </div>

            <h1 style={styles.logoText}>
              DailyMajdoor
            </h1>

          </div>

          <h1 style={styles.mainTitle}>
            Hire Trusted
            <br />
            Workers Easily
          </h1>

          <p style={styles.subtitle}>
            Connect with skilled workers
            near your location anytime.
          </p>

          <div style={styles.tags}>

            <div style={styles.tag}>
              ⚡ Fast Hiring
            </div>

            <div style={styles.tag}>
              🔒 Verified Workers
            </div>

            <div style={styles.tag}>
              📍 Nearby Services
            </div>

          </div>

        </div>

      </div>

      {/* RIGHT SIDE */}

      <div style={styles.rightSection}>

        <div style={styles.card}>

          <div style={styles.smallLogo}>
            D
          </div>

          <h1 style={styles.loginTitle}>
            Welcome Back
          </h1>

          <p style={styles.loginSub}>
            Login to continue
          </p>

          <form onSubmit={loginUser}>

            <select
              style={styles.input}
              value={role}
              onChange={(e) =>
                setRole(e.target.value)
              }
            >

              <option value="customer">
                Customer
              </option>

              <option value="labour">
                Labour
              </option>

            </select>

            <input
              type="email"
              placeholder="Enter Email"
              style={styles.input}
              value={email}
              onChange={(e) =>
                setEmail(e.target.value)
              }
            />

            <input
              type="password"
              placeholder="Enter Password"
              style={styles.input}
              value={password}
              onChange={(e) =>
                setPassword(e.target.value)
              }
            />

            <button style={styles.button}>
              Login
            </button>

          </form>

          <p style={styles.bottomText}>

            Don't have an account?

            <span
              style={styles.link}
              onClick={() =>
                nav("/register")
              }
            >
              Register
            </span>

          </p>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    display: "flex",
    fontFamily: "Arial",
    background: "#0f172a"
  },

  /* LEFT */

  leftSection: {
    width: "55%",
    position: "relative",
    backgroundImage:
      "url('https://images.unsplash.com/photo-1504307651254-35680f356dfd?q=80&w=1400&auto=format&fit=crop')",
    backgroundSize: "cover",
    backgroundPosition: "center",
    display: "flex",
    alignItems: "center",
    padding: "70px"
  },

  overlay: {
    position: "absolute",
    inset: 0,
    background:
      "linear-gradient(to right, rgba(15,23,42,0.92), rgba(15,23,42,0.72))"
  },

  leftContent: {
    position: "relative",
    zIndex: 2,
    color: "white",
    maxWidth: "520px"
  },

  logoBox: {
    display: "flex",
    alignItems: "center",
    gap: "14px",
    marginBottom: "40px"
  },

  logoCircle: {
    width: "55px",
    height: "55px",
    borderRadius: "18px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontWeight: "bold",
    fontSize: "24px",
    color: "white"
  },

  logoText: {
    margin: 0,
    fontSize: "34px"
  },

  mainTitle: {
    fontSize: "72px",
    lineHeight: "82px",
    marginBottom: "24px",
    fontWeight: "800"
  },

  subtitle: {
    fontSize: "20px",
    lineHeight: "36px",
    color: "#cbd5e1",
    marginBottom: "40px"
  },

  tags: {
    display: "flex",
    gap: "18px",
    flexWrap: "wrap"
  },

  tag: {
    background: "rgba(255,255,255,0.08)",
    border: "1px solid rgba(255,255,255,0.08)",
    padding: "14px 22px",
    borderRadius: "16px",
    backdropFilter: "blur(10px)",
    fontWeight: "600"
  },

  /* RIGHT */

  rightSection: {
    width: "45%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "40px"
  },

  card: {
    width: "420px",
    background: "white",
    padding: "45px",
    borderRadius: "30px",
    boxShadow:
      "0 20px 45px rgba(0,0,0,0.15)"
  },

  smallLogo: {
    width: "60px",
    height: "60px",
    borderRadius: "18px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontSize: "24px",
    fontWeight: "bold",
    margin: "0 auto 24px auto"
  },

  loginTitle: {
    textAlign: "center",
    fontSize: "38px",
    marginBottom: "10px",
    color: "#111827"
  },

  loginSub: {
    textAlign: "center",
    color: "#6b7280",
    marginBottom: "35px"
  },

  input: {
    width: "100%",
    padding: "16px",
    marginBottom: "18px",
    borderRadius: "14px",
    border: "1px solid #dbe3ec",
    background: "#f8fafc",
    boxSizing: "border-box",
    fontSize: "15px",
    outline: "none"
  },

  button: {
    width: "100%",
    padding: "16px",
    border: "none",
    borderRadius: "14px",
    background:
      "linear-gradient(135deg,#f97316,#fb923c)",
    color: "white",
    fontSize: "16px",
    fontWeight: "bold",
    cursor: "pointer",
    marginTop: "10px",
    boxShadow:
      "0 10px 25px rgba(249,115,22,0.35)"
  },

  bottomText: {
    textAlign: "center",
    marginTop: "28px",
    color: "#6b7280"
  },

  link: {
    color: "#f97316",
    marginLeft: "6px",
    cursor: "pointer",
    fontWeight: "bold"
  }

};
